  KEY `published_sitemap_index` (`object_published_at`,`is_robots_noindex`,`object_type`,`object_sub_type`)
) ENGINE=InnoDB AUTO_INCREMENT=470 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;
